# Current mindset: Understanding existing systems
class MainframeIntegration:
    def __init__(self, legacy_system):
        self.system = legacy_system  # Existing system with fixed constraints
        self.adapters = []
        self.validate_constraints()

    def validate_constraints(self):
        if self.system.requires_legacy_format:
            raise ValueError("Cannot modify input format")
